import React, { useEffect, useState } from 'react';
import { useAuth } from '../context/AuthContext';
import { apiCall } from '../utils/api';

const AdminProducts = () => {
  const { user, token } = useAuth();
  const [products, setProducts] = useState([]);
  const [loading, setLoading] = useState(true);
  const [form, setForm] = useState({
    name: '',
    description: '',
    price: '',
    category: '',
    brand: '',
    image: '',
    stock: ''
  });
  const [editingId, setEditingId] = useState(null);
  const [error, setError] = useState('');

  useEffect(() => {
    if (user?.role === 'admin' && user?.email === 'admin@sunelectronics.com') {
      fetchProducts();
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [user]);

  const fetchProducts = async () => {
    setLoading(true);
    try {
      const res = await apiCall.get('/products', { headers: { Authorization: `Bearer ${token}` } });
      setProducts(res.data.products || []);
    } catch (err) {
      console.error('Error fetching products', err);
    } finally {
      setLoading(false);
    }
  };

  const handleChange = (e) => {
    const { name, value } = e.target;
    setForm(prev => ({ ...prev, [name]: value }));
  };

  const handleAdd = async (e) => {
    e.preventDefault();
    setError('');
    try {
      const payload = {
        name: form.name,
        description: form.description,
        price: parseFloat(form.price),
        category: form.category,
        brand: form.brand,
        image: form.image,
        stock: parseInt(form.stock, 10)
      };
      if (editingId) {
        // update existing product
        await apiCall.put(`/products/${editingId}`, payload, { headers: { Authorization: `Bearer ${token}` } });
        setEditingId(null);
      } else {
        await apiCall.post('/products', payload, { headers: { Authorization: `Bearer ${token}` } });
      }
      setForm({ name: '', description: '', price: '', category: '', brand: '', image: '', stock: '' });
      fetchProducts();
    } catch (err) {
      console.error(editingId ? 'Failed to update product' : 'Failed to add product', err);
      setError(err.response?.data?.message || (editingId ? 'Failed to update product' : 'Failed to add product'));
    }
  };

  const handleDelete = async (id) => {
    if (!window.confirm('Delete this product?')) return;
    try {
      await apiCall.delete(`/products/${id}`, { headers: { Authorization: `Bearer ${token}` } });
      if (editingId === id) setEditingId(null);
      fetchProducts();
    } catch (err) {
      console.error('Failed to delete', err);
    }
  };

  const handleEdit = (product) => {
    setEditingId(product._id);
    setForm({
      name: product.name,
      description: product.description || '',
      price: product.price || '',
      category: product.category || '',
      brand: product.brand || '',
      image: product.image || '',
      stock: product.stock != null ? product.stock.toString() : ''
    });
  };

  const handleToggle = async (product) => {
    const newStock = product.stock > 0 ? 0 : 1;
    try {
      await apiCall.put(`/products/${product._id}`, { stock: newStock }, { headers: { Authorization: `Bearer ${token}` } });
      if (editingId === product._id && newStock === 0) {
        // if disabling while editing, clear form
        setEditingId(null);
        setForm({ name: '', description: '', price: '', category: '', brand: '', image: '', stock: '' });
      }
      fetchProducts();
    } catch (err) {
      console.error('Failed to toggle visibility', err);
    }
  };


  if (!(user?.role === 'admin' && user?.email === 'admin@sunelectronics.com')) {
    return <div>Access denied.</div>;
  }

  return (
    <div className="admin-product-manager">
      <h2>Product Management</h2>

      <form className="product-form" onSubmit={handleAdd}>
        {error && <p className="error">{error}</p>}
        <input name="name" placeholder="Name" value={form.name} onChange={handleChange} required />
        <input name="description" placeholder="Description" value={form.description} onChange={handleChange} required />
        <input name="price" placeholder="Price" value={form.price} onChange={handleChange} required type="number" step="0.01" />
        <input name="category" placeholder="Category" value={form.category} onChange={handleChange} required />
        <input name="brand" placeholder="Brand" value={form.brand} onChange={handleChange} />
        <input name="image" placeholder="Image URL" value={form.image} onChange={handleChange} />
        <input name="stock" placeholder="Stock" value={form.stock} onChange={handleChange} required type="number" />
        <button type="submit">Add Product</button>
      </form>

      {loading ? (
        <p>Loading...</p>
      ) : (
        <div className="product-list">
          {products.length === 0 && <p>No products available</p>}
          {products.map(p => (
            <div key={p._id} className="product-row">
              <span>{p.name} ({p.stock} in stock)</span>
              <button onClick={() => handleDelete(p._id)}>Remove</button>
            </div>
          ))}
        </div>
      )}
    </div>
  );
};

export default AdminProducts;
